class JWTServiceManager:
    def __init__(self):
        self.jwt_wrapper = JWTWrapper()
        self.service_configs = {}
    
    def register_internal_service(self, service_name: str, secret: str):
        key_id = f"internal_{service_name}"
        self.jwt_wrapper.register_secret(key_id, secret, algorithm='HS256')
        self.service_configs[service_name] = {
            'type': 'internal',
            'key_id': key_id,
            'algorithm': 'HS256'
        }
    
    def register_public_service(self, service_name: str, private_key: Optional[str] = None,
                               public_key: Optional[str] = None):
        key_id = f"public_{service_name}"
        self.jwt_wrapper.register_rsa_keys(key_id, private_key, public_key, algorithm='RS256')
        self.service_configs[service_name] = {
            'type': 'public',
            'key_id': key_id,
            'algorithm': 'RS256'
        }
    
    def create_service_token(self, service_name: str, payload: Dict[str, Any],
                            expires_in: int = 3600) -> str:
        if service_name not in self.service_configs:
            raise ValueError(f"Service {service_name} not registered")
        
        config = self.service_configs[service_name]
        return self.jwt_wrapper.create_token(payload, config['key_id'], expires_in)
    
    def verify_service_token(self, service_name: str, token: str,
                            verify_exp: bool = True) -> Dict[str, Any]:
        if service_name not in self.service_configs:
            raise ValueError(f"Service {service_name} not registered")
        
        config = self.service_configs[service_name]
        return self.jwt_wrapper.verify_token(token, config['key_id'], verify_exp=verify_exp)
    
    def verify_any_service_token(self, token: str, verify_exp: bool = True) -> Dict[str, Any]:
        key_ids = [config['key_id'] for config in self.service_configs.values()]
        return self.jwt_wrapper.verify_token_multi_key(token, key_ids, verify_exp=verify_exp)